// Validate onboarding payload
const body = $input.first().json.body || $input.first().json;

// ── Shell-metacharacter sanitiser (F-1 fix) ──────────────────────────────────
function sanitizeArg(val, fieldName) {
  if (typeof val !== 'string') return val;
  if (/[^a-zA-Z0-9_.\/\-]/.test(val)) {
    throw new Error(
      `Input '${fieldName}' contains disallowed shell characters: ${val}. ` +
      'Only alphanumerics, path separators (/), dots, dashes and underscores are allowed.'
    );
  }
  return val;
}

// ── Path-prefix restriction (F-2 fix) ────────────────────────────────────────
const ALLOWED_PREFIX = '/app/clara_pipeline/data/';
function restrictPath(val, fieldName) {
  if (!val.startsWith(ALLOWED_PREFIX)) {
    throw new Error(
      `'${fieldName}' must be within ${ALLOWED_PREFIX}. Got: ${val}`
    );
  }
  return val;
}

const rawAccountId = body.account_id;
const rawTranscriptPath = body.transcript_path;
const force = body.force || false;
const rawModel = body.model || process.env.OLLAMA_MODEL || 'mistral';
const rawOllamaUrl = body.ollama_url || process.env.OLLAMA_URL || 'http://host.docker.internal:11434';

if (!rawAccountId) {
  throw new Error('Missing required field: account_id');
}

if (!rawTranscriptPath) {
  throw new Error('Missing required field: transcript_path');
}

// Validate account_id format (fixed allowlist — no sanitiseArg needed, regex is strict)
if (!/^CLARA-\d{4}-\d{3}$/.test(rawAccountId)) {
  throw new Error(`Invalid account_id format: ${rawAccountId}. Expected CLARA-YYYY-NNN.`);
}
const accountId = rawAccountId;

// Sanitise and restrict paths
const transcriptPath = restrictPath(sanitizeArg(rawTranscriptPath, 'transcript_path'), 'transcript_path');
const model = sanitizeArg(rawModel, 'model');
let ollamaUrl;
try {
  const u = new URL(rawOllamaUrl);
  if (!['http:', 'https:'].includes(u.protocol)) throw new Error('protocol');
  ollamaUrl = rawOllamaUrl;
} catch {
  throw new Error(`'ollama_url' is not a valid http/https URL: ${rawOllamaUrl}`);
}

const fs = require('fs');
if (!fs.existsSync(transcriptPath)) {
  throw new Error(`Transcript file not found: ${transcriptPath}`);
}

// Verify v1 memo exists — onboarding cannot proceed without it
const v1MemoPath = `/app/clara_pipeline/outputs/accounts/${accountId}/v1/account_memo.json`;
if (!fs.existsSync(v1MemoPath)) {
  throw new Error(
    `v1 account memo not found for ${accountId}. ` +
    `Run Pipeline A (demo call) first. Expected at: ${v1MemoPath}`
  );
}

// Read v1 memo for context
const v1Memo = JSON.parse(fs.readFileSync(v1MemoPath, 'utf8'));

return [{
  json: {
    account_id: accountId,
    transcript_path: transcriptPath,
    force,
    model,
    ollama_url: ollamaUrl,
    v1_memo_path: v1MemoPath,
    company_name: v1Memo.company?.name || '[Unknown]',
    v1_extraction_confidence: v1Memo.extraction_confidence || null,
    received_at: new Date().toISOString(),
    request_id: `req-${Date.now()}`
  }
}];

// Idempotency check — skip if v2 already exists (unless force=true)
const fs = require('fs');
const accountId = $input.first().json.account_id;
const force = $input.first().json.force;

const v2MemoPath = `/app/clara_pipeline/outputs/accounts/${accountId}/v2/account_memo.json`;
const v2Exists = fs.existsSync(v2MemoPath);

if (v2Exists && !force) {
  return [{ json: { ...$input.first().json, skip_reason: 'v2_already_exists', should_skip: true } }];
}

return [{ json: { ...$input.first().json, should_skip: false } }];

// Parse Script 3 output
const stdout = $input.first().json.stdout || '';
const exitCode = $input.first().json.exitCode;
const accountId = $input.first().json.account_id;

if (exitCode !== 0) {
  throw new Error(`Script 3 failed (exit ${exitCode}):\n${stdout}`);
}

// Extract metrics from output
const changedMatch = stdout.match(/Fields updated:\s+(\d+)/);
const confirmedMatch = stdout.match(/Newly confirmed:\s+(\d+)/);
const resolvedMatch = stdout.match(/Unknowns resolved:\s+(\d+)/);
const remainingMatch = stdout.match(/Unknowns remaining:\s+(\d+)/);
const goLiveMatch = stdout.match(/Go-live ready:\s+([✅❌].*)/);

const fields_changed = changedMatch ? parseInt(changedMatch[1]) : 0;
const fields_confirmed = confirmedMatch ? parseInt(confirmedMatch[1]) : 0;
const unknowns_resolved = resolvedMatch ? parseInt(resolvedMatch[1]) : 0;
const unknowns_remaining = remainingMatch ? parseInt(remainingMatch[1]) : 0;
const go_live_ready = goLiveMatch ? goLiveMatch[1].includes('YES') : false;

// Spec status
const v2Dir = `/app/clara_pipeline/outputs/accounts/${accountId}/v2`;
const specPath = `${v2Dir}/retell_agent_spec.json`;
const draftPath = `${v2Dir}/retell_agent_spec.draft.json`;
const changelogMdPath = `${v2Dir}/changes.md`;
const changelogJsonPath = `${v2Dir}/changes.json`;

const fs = require('fs');
const specStatus = fs.existsSync(specPath) ? 'ready' : (fs.existsSync(draftPath) ? 'draft' : 'error');

const prevJson = $input.first().json;

return [{
  json: {
    ...prevJson,
    fields_changed,
    fields_confirmed,
    unknowns_resolved,
    unknowns_remaining,
    go_live_ready,
    spec_status: specStatus,
    spec_path: fs.existsSync(specPath) ? specPath : draftPath,
    v2_memo_path: `${v2Dir}/account_memo.json`,
    changelog_md_path: changelogMdPath,
    changelog_json_path: changelogJsonPath,
    script3_stdout: stdout,
    script3_status: 'ok'
  }
}];

// Read changelog and v2 memo for response enrichment
const fs = require('fs');
const d = $input.first().json;

let changelogJson = {};
let v2Memo = {};

try {
  if (fs.existsSync(d.changelog_json_path)) {
    changelogJson = JSON.parse(fs.readFileSync(d.changelog_json_path, 'utf8'));
  }
} catch(e) { console.log('changelog read warn:', e.message); }

try {
  if (fs.existsSync(d.v2_memo_path)) {
    v2Memo = JSON.parse(fs.readFileSync(d.v2_memo_path, 'utf8'));
  }
} catch(e) { console.log('v2 memo read warn:', e.message); }

return [{
  json: {
    ...d,
    changelog_summary: {
      fields_changed: changelogJson.stats?.fields_changed || d.fields_changed,
      fields_newly_confirmed: changelogJson.stats?.fields_newly_confirmed || d.fields_confirmed,
      unknowns_resolved: changelogJson.unknowns_resolved?.length || d.unknowns_resolved,
      unknowns_remaining: changelogJson.unknowns_remaining || [],
      go_live_ready: changelogJson.go_live_ready || d.go_live_ready,
      sections_affected: changelogJson.summary_sections_affected || []
    },
    v2_company_name: v2Memo.company?.name || d.company_name
  }
}];

// Append to pipeline log
const fs = require('fs');
const path = require('path');
const logPath = '/app/clara_pipeline/outputs/pipeline_log.json';

let log = [];
try {
  if (fs.existsSync(logPath)) {
    log = JSON.parse(fs.readFileSync(logPath, 'utf8'));
  }
} catch(e) {}

const d = $input.first().json;

const entry = {
  timestamp: new Date().toISOString(),
  pipeline: 'B',
  account_id: d.account_id,
  company_name: d.v2_company_name || d.company_name,
  transcript: d.transcript_path,
  stage: 'onboarding_call',
  fields_changed: d.fields_changed,
  fields_confirmed: d.fields_confirmed,
  unknowns_resolved: d.unknowns_resolved,
  unknowns_remaining: d.unknowns_remaining,
  go_live_ready: d.go_live_ready,
  spec_status: d.spec_status,
  outputs: {
    v2_memo: d.v2_memo_path,
    v2_spec: d.spec_path,
    changelog_md: d.changelog_md_path,
    changelog_json: d.changelog_json_path
  }
};

log.push(entry);
fs.mkdirSync(path.dirname(logPath), { recursive: true });
fs.writeFileSync(logPath, JSON.stringify(log, null, 2));

return [{ json: { ...d, log_entry: entry } }];

const error = $input.first().json;
return [{
  json: {
    message: error.message || 'Unknown error in Pipeline B',
    node: error.node || 'unknown',
    timestamp: new Date().toISOString()
  }
}];
